@media print {
  @page { size: A4 landscape; margin: 8mm; }
  .print-format table { font-size: 10px; }
  .print-format td, .print-format th { padding: 3px 5px !important; }
}

@media print {
  @page { size: A4 landscape; margin: 8mm; }
  .print-format table { font-size: 10px; }
  .print-format td, .print-format th { padding: 3px 5px !important; }
}
.pp-print-head{display:flex;justify-content:space-between;align-items:flex-start;margin-bottom:10px;}
.pp-print-company{font-size:22px;font-weight:700;}
.pp-print-meta{font-size:12px;line-height:1.6;}
.pp-print-table{width:100%;border-collapse:collapse;margin-top:8px;}
.pp-print-table th,.pp-print-table td{border:1px solid #111;padding:4px 6px;}
.pp-print-table th{background:#f1f5f9;}
.pp-print-total td{font-weight:700;background:#f8fafc;}
.pp-print-sign{margin-top:20px;width:100%;border-collapse:collapse;}
.pp-print-sign td{padding-top:30px;width:33.33%;text-align:center;}
.pp-sign-line{border-top:1px solid #111;padding-top:6px;display:inline-block;min-width:160px;}
